export var CUSTOM_VALUE_PATTERN = /\{\{val\((\d+)\)\}\}|\{\{col\((\d+)\)\}\}|\{\{per\((\d+)\)\}\}|\{\{splitper\((\d+)\)\}\}|\{\{maxper\((\d+)\)\}\}|\{\{geo\(([a-z0-9\-\_]+)\)\}\}|\{\{clr\}\}|\{\{valatpos\((\d+)\)\[(\d+)\]\}\}|\{\{symbol\(([a-z0-9\-\_]*)(?:,\s*({{clr}}|[a-z0-9\-_]+)\s*)?\)\}\}/gi, // regxr
    RGBA_PATTERN = /^rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*(\d+(?:\.\d+)?))?\)$/i,
    PERCENT_PATTERN = /\{\{per\((\d+)\)\}\}|\{\{splitper\((\d+)\)\}\}|\{\{maxper\((\d+)\)\}\}/gi,
    STORED_DATA_PATTERN = /\{\{([^)]+)\}\}/,
    HIGHLIGHT_EFFECT_REGEX = /(illuminate|moody|flip|boxShadow|invert|ridge)/,
    UNHIGHLIGHT_EFFECT_REGEX = /(fadeOut|blur|grayscale|saturate)/,
    Console = window.console,
    tempCanvasContext = () => document.createElement('canvas').getContext('2d'),
    tempSVGPath = () => document.createElementNS(d3_namespaces.svg, 'path');

export var getDocumentWindow = function(node) {
    if (node && node.document) {
        return node.document;
    }
    return window;
};

